import React, { useState, useEffect } from 'react';
import api from '../api/axios';

const Order = () => {
  const [orders, setOrders] = useState([]);

  // Hàm load danh sách đơn hàng
  const fetchOrders = async () => {
    try {
      const res = await api.get('/admin/orders');
      setOrders(res.data);
    } catch (err) {
      console.error('Lỗi tải đơn hàng', err);
    }
  };

  useEffect(() => {
    fetchOrders();
  }, []);

  // Hàm gọi API đổi trạng thái khi Admin bấm nút
  const updateStatus = async (id, newStatus) => {
    if (window.confirm(`Xác nhận chuyển đơn hàng này sang trạng thái: ${newStatus}?`)) {
      try {
        const res = await api.put(`/admin/orders/status/${id}`, { status: newStatus });
        if (res.data) {
          alert('Cập nhật thành công!');
          fetchOrders(); // Tải lại bảng ngay lập tức
        }
      } catch (err) {
        alert('Lỗi cập nhật!');
      }
    }
  };

  return (
    <div className="align-center">
      <h2 className="text-center">QUẢN LÝ ĐƠN HÀNG</h2>
      <table className="datatable" border="1" width="100%">
        <tbody>
          <tr className="datatable">
            <th>Mã đơn</th>
            <th>Ngày đặt</th>
            <th>Khách hàng</th>
            <th>SĐT / Địa chỉ</th>
            <th>Tổng tiền</th>
            <th>Trạng thái hiện tại</th>
            <th>Hành động (Duyệt đơn)</th>
          </tr>
          
          {orders.map((item) => (
            <tr key={item._id} className="datatable">
              <td>{item._id.slice(-6).toUpperCase()}</td>
              <td>{new Date(item.cdate).toLocaleString()}</td>
              <td>{item.customer?.name}</td>
              <td>{item.phone} <br/> {item.address}</td>
              <td style={{ color: 'red', fontWeight: 'bold' }}>{item.total.toLocaleString()} đ</td>
              <td><strong>{item.status}</strong></td>
              <td>
                {/* Logic hiển thị nút tùy theo trạng thái */}
                {item.status === 'PENDING' && (
                  <>
                    <button onClick={() => updateStatus(item._id, 'APPROVED')} style={{ background: '#17a2b8', color: 'white', padding: '5px', margin: '2px' }}>Duyệt đơn</button>
                    <button onClick={() => updateStatus(item._id, 'CANCELED')} style={{ background: '#dc3545', color: 'white', padding: '5px', margin: '2px' }}>Hủy đơn</button>
                  </>
                )}
                {item.status === 'APPROVED' && (
                  <button onClick={() => updateStatus(item._id, 'SHIPPING')} style={{ background: '#fd7e14', color: 'white', padding: '5px' }}>Giao cho Shipper</button>
                )}
                {item.status === 'SHIPPING' && (
                  <button onClick={() => updateStatus(item._id, 'COMPLETED')} style={{ background: '#28a745', color: 'white', padding: '5px' }}>Đã giao xong</button>
                )}
                {item.status === 'COMPLETED' && <span style={{ color: 'green' }}>Hoàn tất ✔️</span>}
                {item.status === 'CANCELED' && <span style={{ color: 'red' }}>Đã hủy ❌</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Order;
